namespace sv_ee6b192e9297424ea2537dbf19ebebe6.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_ee6b192e9297424ea2537dbf19ebebe6.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 25),
            new(2, "Margherita Pizza", "Simple pizza with tomato sauce, fresh mozzarella, and basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
            new(4, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 30),
        },
        [2] = new List<Recipe>
        {
            new(5, "Chicken Tikka Masala", "Grilled chicken in a creamy spiced tomato sauce.", 40),
            new(6, "Palak Paneer", "Fresh spinach curry with soft paneer cubes.", 30),
            new(7, "Biryani", "Fragrant layered rice dish with spices and marinated meat.", 60),
            new(8, "Samosa", "Crispy pastry filled with spiced potatoes and peas.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Sushi Rolls", "Vinegared rice and fresh fish wrapped in nori seaweed.", 45),
            new(10, "Ramen", "Rich broth with wheat noodles, pork, egg, and toppings.", 120),
            new(11, "Tempura", "Lightly battered and deep-fried vegetables and shrimp.", 25),
            new(12, "Miso Soup", "Traditional soup with dashi broth, tofu, and seaweed.", 15),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_ee6b192e9297424ea2537dbf19ebebe6.Services
@rendermode InteractiveServer
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IAsyncDisposable

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <h3>Recipes</h3>
    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <ul>
            @foreach (var recipe in GetSortedRecipes())
            {
                <li>
                    <strong>@recipe.Title</strong> — @recipe.Description
                    <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousCuisineId = CuisineId;

        await base.SetParametersAsync(parameters);

        // Only reload data when the cuisine changes, not when sort changes
        if (CuisineId != previousCuisineId || (_recipes is null && _error is null))
        {
            await LoadRecipesAsync();
        }
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
        _loadCts = new CancellationTokenSource();
        var cancellationToken = _loadCts.Token;

        _error = null;

        // Show "Refreshing…" if we already have data, otherwise show full loading
        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        StateHasChanged();

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            // Don't update state if cancelled during await
            if (cancellationToken.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
            _error = null;
        }
        catch (OperationCanceledException)
        {
            // Request was intentionally cancelled; do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
        {
            return Enumerable.Empty<Recipe>();
        }

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }
}

